def heuristic_deadline_disable(strategy_name: str, stats: dict, state_strategy: dict, today_iso: str) -> tuple:
    """Auto-disable a strategy that reached its hard deadline with zero lifetime trades."""
    deadline = state_strategy.get('deadline_disable_date')
    if not deadline:
        return False, ''
    if stats.get('trades_lifetime', 0) > 0:
        return False, ''
    try:
        from datetime import date as _date
        if _date.fromisoformat(today_iso) >= _date.fromisoformat(deadline):
            return True, f'deadline {deadline} reached with 0 lifetime trades -- auto-disabled'
    except (ValueError, TypeError):
        return False, ''
    return False, ''
